+  return framesToShow
+    .slice(0, maxFrames)
+    .map((f, i) => {
+      const file = f.filename || f.absPath || f.module || "unknown";
+      const func = f.function || "(anonymous)";
+      const line = f.lineNo || f.lineno;
+      const col = f.colNo || f.colno;
+      const loc = line ? `:${line}${col ? `:${col}` : ""}` : "";
