+      throw new Error(
+        result.exceptionDetails.exception?.description ||
+          result.exceptionDetails.text
+      );
+    }
+    return result.result?.value;
+  }
+
+  async screenshot(sessionId, timeout = 10000) {
+    const { data } = await this.send(
+      "Page.captureScreenshot",
+      { format: "png" },
+      sessionId,
+      timeout
+    );
