+  async navigate(sessionId, url, timeout = 30000) {
+    await this.send("Page.navigate", { url }, sessionId, timeout);
+  }
+
+  async getFrameTree(sessionId) {
+    const { frameTree } = await this.send("Page.getFrameTree", {}, sessionId);
