+      {
+        expression,
+        contextId: executionContextId,
+        returnByValue: true,
+        awaitPromise: true,
+      },
+      sessionId,
+      timeout
+    );
+
+    if (result.exceptionDetails) {
+      throw new Error(
+        result.exceptionDetails.exception?.description ||
+          result.exceptionDetails.text
+      );
+    }
+    return result.result?.value;
+  }
+
+  close() {
+    this.ws.close();
+  }
+}

