+    for (const btn of buttons) {
+      if (!isVisible(btn)) continue;
+      const text = (btn.textContent || '').trim().toLowerCase();
+      if (singleWordPatterns.some(p => text === p)) {
+        btn.click();
+        clicked.push('Generic (single word)');
+        return clicked;
+      }
+    }
+  }
+
+  return clicked;
