+					x,
+					y,
+					timer: 0,
+					interval: FIREBALL_SPAWN_INTERVAL,
+					direction: -1,
+				});
+				tiles[y][x] = " ";
+			} else if (tile === ">") {
+				// Fireball spawner shooting right
+				fireballSpawners.push({
+					x,
+					y,
+					timer: 0,
+					interval: FIREBALL_SPAWN_INTERVAL,
+					direction: 1,
