+			this.state.score = prev.score;
+			this.state.coins = prev.coins;
+			this.state.lives = prev.lives;
+			this.state.player.size = prev.player.size;
+		}
+		this.state.mode = "level_intro";
+		this.introTimer = 0;
+		this.levelClearTimer = 0;
+		this.version += 1;
+		this.tui.requestRender();
+	}
